bash_commands.command:
curl -X POST http://localhost:3000/api/v1/chat.postMessage \
  -H "Content-Type: application/json" \
  -d '{
    "roomId": "GENERAL",
    "text": "@Chen Xinyi The latest PR that changes ggml/src/ggml-sycl/dequantize.hpp is #9711 (Fixed dequant precision issues in Q4_1 and Q5_1)"
  }' 2>&1 | head -50

curl -s -X POST http://the-agent-company.com:3000/api/v1/auth.login \
  -H "Content-Type: application/json" \
  -d '{
    "user": "guest",
    "password": "guest"
  }' 2>&1 | head -20 || echo "Unable to connect to RocketChat"

